create table if not exists legacy_board (id integer primary key autoincrement,title varchar(100) not null,content text not null,created_at timestamp not null);
create table if not exists legacy_vendor (id integer primary key autoincrement,code varchar(30) not null unique,name varchar(80) not null,credit_limit integer not null check (credit_limit >= 0));
create table if not exists legacy_inventory (id integer primary key autoincrement,sku varchar(40) not null unique,name varchar(120) not null,quantity integer not null check (quantity >= 0));
create table if not exists legacy_job_queue (id integer primary key autoincrement,job_type varchar(30) not null,payload varchar(200) not null,status varchar(30) not null check (status in ('READY','PROCESSING','DONE','FAILED')),attempt_count integer not null default 0,force_error_code varchar(40),created_at timestamp not null);
create table if not exists legacy_settlement (id integer primary key autoincrement,vendor_code varchar(30) not null,amount integer not null check (amount > 0),business_date varchar(10) not null,status varchar(30) not null check (status in ('REQUESTED','APPROVED','CANCELED')),unique (vendor_code,business_date));
create table if not exists legacy_file_manifest (id integer primary key autoincrement,file_name varchar(200) not null unique,expected_rows integer not null check (expected_rows > 0),status varchar(30) not null check (status in ('REGISTERED','DONE','FAILED')));